"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[4512],{74512:function(n){n.exports=JSON.parse('{"slug":"doc-z4eg79","title":"位置外推与插值","description":"","date":null,"tags":[],"category":"LLM","categoryId":"llm","content":"# 位置外推与插值\\n\\n> **更新日期**: 2026-03-13\\n> **版本**: v1.0\\n> **难度**: 高级\\n> **预计阅读时间**: 45 分钟\\n\\n---\\n\\n## 目录\\n\\n1. [长上下文挑战](#长上下文挑战)\\n2. [位置插值 PI](#位置插值-pi)\\n3. [NTK-aware 扩展](#ntk-aware-扩展)\\n4. [YaRN](#yarn)\\n5. [面试要点](#面试要点)\\n\\n---\\n\\n## 长上下文挑战\\n\\n### 外推问题\\n\\n```\\n预训练: 最大长度 4K\\n推理时: 需要 32K\\n\\n问题:\\n- 位置编码未见过长序列\\n- 注意力机制失效\\n- 性能急剧下降\\n```\\n\\n---\\n\\n## 位置插值 PI\\n\\n### 原理\\n\\n```\\n原始位置: [0, 1, 2, ..., 4095]\\n插值后: [0, 0.5, 1, ..., 2047.5] (扩展到 8K)\\n\\n缩放因子 s = 目标长度 / 训练长度\\n```\\n\\n### 实现\\n\\n```python\\ndef position_interpolation(pos, scale_factor):\\n    return pos / scale_factor\\n```\\n\\n---\\n\\n## NTK-aware 扩展\\n\\n### 原理\\n\\n高频信息外推，低频信息插值。\\n\\n```python\\ndef ntk_scaling(base, dim, max_seq_len, scaling_factor):\\n    # 高频不插值，低频插值\\n    inv_freq = 1.0 / (base ** (torch.arange(0, dim, 2).float() / dim))\\n    inv_freq /= scaling_factor\\n    return inv_freq\\n```\\n\\n---\\n\\n## YaRN\\n\\n### 特点\\n\\n- 结合 PI 和 NTK\\n- 温度缩放注意力\\n- 更好的长上下文性能\\n\\n---\\n\\n## 面试要点\\n\\n**Q1: PI 和 NTK 的区别？**\\n\\nA:\\n- PI: 所有频率都插值\\n- NTK: 高频外推，低频插值\\n\\n**Q2: 长上下文的主要挑战？**\\n\\nA:\\n- 位置编码外推\\n- 注意力复杂度 O(n\xb2)\\n- 显存占用\\n","filePath":"长上下文/位置外推与插值.md"}')}}]);